CREATE OR REPLACE FUNCTION public.handle_new_user_profile() RETURNS TRIGGER AS $$ BEGIN INSERT INTO public.student_profiles (id, full_name, account_status, onboarding_step, created_at) VALUES ( NEW.id, COALESCE(NEW.raw_user_meta_data->>'full_name', split_part(NEW.email, '@', 1)), 'pending', 'pending_plan', NOW() ) ON CONFLICT (id) DO NOTHING; RETURN NEW; END; $$ LANGUAGE plpgsql SECURITY DEFINER; DROP TRIGGER IF EXISTS on_auth_user_created_profile ON auth.users; CREATE TRIGGER on_auth_user_created_profile AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user_profile();